namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndex()
    {
        var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 3, 5);
        Assert.Equal(3, list.PageIndex);
    }

    [Fact]
    public void Constructor_SetsTotalPages_SinglePage()
    {
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 10);
        Assert.Equal(1, list.TotalPages);
    }

    [Fact]
    public void Constructor_SetsTotalPages_MultiplePages()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 25, 1, 10);
        Assert.Equal(3, list.TotalPages);
    }

    [Fact]
    public void Constructor_SetsTotalPages_RoundsUp()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 11, 1, 10);
        Assert.Equal(2, list.TotalPages);
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 3, 1, 10);
        Assert.Equal(3, list.Count);
        Assert.Contains("b", list);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 1, 10);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 2, 10);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 2, 10);
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 1, 10);
        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPageItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result.First());
        Assert.Equal(20, result.Last());
    }

    [Fact]
    public void Create_FirstPage_StartsFromBeginning()
    {
        var source = Enumerable.Range(1, 15).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.Equal(5, result.Count);
        Assert.Equal(1, result.First());
        Assert.Equal(5, result.Last());
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.Equal(3, result.Count);
        Assert.Equal(11, result.First());
        Assert.Equal(13, result.Last());
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }

    [Fact]
    public void Create_SingleItemPage_WorksCorrectly()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 1);

        Assert.Single(result);
        Assert.Equal(3, result.First());
        Assert.Equal(5, result.TotalPages);
    }
}

