using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        TestHelpers.DrainNotificationQueue();
        _service = new NotificationService();
    }

    public void Dispose()
    {
        _service.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();
        Assert.Null(notification);
    }

    [Fact]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        _service.SendNotification("Course", "100", EntityOperation.CREATE, "admin");
        var notification = _service.ReceiveNotification();

        Assert.Equal("admin", notification!.CreatedBy);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Course", "100", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("System", notification!.CreatedBy);
    }

    [Fact]
    public void SendNotification_Create_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("New Student 'John Doe' has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_Update_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("Course 'Chemistry' has been updated", notification!.Message);
    }

    [Fact]
    public void SendNotification_Delete_GeneratesCorrectMessage()
    {
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("Department 'Engineering' has been deleted", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
    {
        _service.SendNotification("Instructor", "7", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("New Instructor (ID: 7) has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        _service.SendNotification("Student", "1", "Jane Doe", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("Jane Doe", notification!.Message);
    }

    [Fact]
    public void SendNotification_SetsIsReadToFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.False(notification!.IsRead);
    }

    [Fact]
    public void SendNotification_SetsOperationString()
    {
        _service.SendNotification("Course", "1", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        Assert.Equal("UPDATE", notification!.Operation);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;
        var notification = _service.ReceiveNotification();

        Assert.InRange(notification!.CreatedAt, before, after);
    }

    [Fact]
    public void ReceiveNotification_DequeuesInFifoOrder()
    {
        _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _service.SendNotification("Student", "2", "Second", EntityOperation.CREATE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        Assert.Equal("1", first!.EntityId);
        Assert.Equal("2", second!.EntityId);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WithNullDisplayName_UsesIdFallback()
    {
        _service.SendNotification("Student", "99", null, EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 99", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
    {
        _service.SendNotification("Student", "99", "", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 99", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdFallback()
    {
        _service.SendNotification("Student", "99", "   ", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 99", notification!.Message);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_AllEnqueued()
    {
        for (int i = 0; i < 10; i++)
        {
            _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        int count = 0;
        while (_service.ReceiveNotification() != null) count++;
        Assert.Equal(10, count);
    }
}

