using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestHelpers
{
    public static SchoolContext CreateContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var context = CreateContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept1 = new Department
        {
            DepartmentID = 1,
            Name = "English",
            Budget = 100000m,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 200000m,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor2.ID
        };
        context.Departments.AddRange(dept1, dept2);
        context.SaveChanges();

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = 2
        };
        var course3 = new Course
        {
            CourseID = 2021,
            Title = "Composition",
            Credits = 4,
            DepartmentID = 1
        };
        context.Courses.AddRange(course1, course2, course3);
        context.SaveChanges();

        instructor1.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor1.ID,
            CourseID = 1050
        });
        context.SaveChanges();

        var student1 = new Student
        {
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        var student2 = new Student
        {
            LastName = "Alonso",
            FirstMidName = "Meredith",
            EnrollmentDate = DateTime.Parse("2012-09-01")
        };
        var student3 = new Student
        {
            LastName = "Anand",
            FirstMidName = "Arturo",
            EnrollmentDate = DateTime.Parse("2013-09-01")
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        context.Enrollments.AddRange(
            new Enrollment { StudentID = student1.ID, CourseID = 1050, Grade = Grade.A },
            new Enrollment { StudentID = student1.ID, CourseID = 4022, Grade = Grade.C },
            new Enrollment { StudentID = student2.ID, CourseID = 1050, Grade = Grade.B },
            new Enrollment { StudentID = student3.ID, CourseID = 2021 }
        );
        context.SaveChanges();
    }

    /// <summary>
    /// Drains any notifications left over from previous tests (static queue).
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }
}

