using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };
        Assert.Equal("Smith, John", student.FullName);
    }

    [Fact]
    public void FullName_WithDifferentNames()
    {
        var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane" };
        Assert.Equal("Doe, Jane", instructor.FullName);
    }
}

public class StudentTests
{
    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();
        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Properties_CanBeSetAndRetrieved()
    {
        var date = new DateTime(2020, 9, 1);
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = date
        };

        Assert.Equal(1, student.ID);
        Assert.Equal("Test", student.LastName);
        Assert.Equal("Student", student.FirstMidName);
        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Enrollments_DefaultsToNull()
    {
        var student = new Student();
        Assert.Null(student.Enrollments);
    }

    [Fact]
    public void Enrollments_CanBeAssigned()
    {
        var student = new Student();
        student.Enrollments = new List<Enrollment> { new Enrollment { EnrollmentID = 1 } };
        Assert.Single(student.Enrollments);
    }
}

public class InstructorTests
{
    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();
        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Properties_CanBeSetAndRetrieved()
    {
        var date = new DateTime(2000, 1, 15);
        var instructor = new Instructor
        {
            ID = 5,
            LastName = "Instructor",
            FirstMidName = "Test",
            HireDate = date
        };

        Assert.Equal(5, instructor.ID);
        Assert.Equal(date, instructor.HireDate);
    }

    [Fact]
    public void CourseAssignments_CanBeSetAndRetrieved()
    {
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1 },
                new CourseAssignment { CourseID = 2 }
            }
        };

        Assert.Equal(2, instructor.CourseAssignments.Count);
    }

    [Fact]
    public void OfficeAssignment_CanBeSetAndRetrieved()
    {
        var instructor = new Instructor
        {
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };

        Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
    }
}

public class CourseTests
{
    [Fact]
    public void Properties_CanBeSetAndRetrieved()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/test.jpg"
        };

        Assert.Equal(1050, course.CourseID);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void NavigationProperties_DefaultToNull()
    {
        var course = new Course();
        Assert.Null(course.Department);
        Assert.Null(course.Enrollments);
        Assert.Null(course.CourseAssignments);
    }
}

public class DepartmentTests
{
    [Fact]
    public void Properties_CanBeSetAndRetrieved()
    {
        var date = new DateTime(2007, 9, 1);
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = date,
            InstructorID = 5
        };

        Assert.Equal(1, department.DepartmentID);
        Assert.Equal("Engineering", department.Name);
        Assert.Equal(350000m, department.Budget);
        Assert.Equal(date, department.StartDate);
        Assert.Equal(5, department.InstructorID);
    }

    [Fact]
    public void InstructorID_IsNullable()
    {
        var department = new Department { Name = "Test" };
