using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsEmptyList()
    {
        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        Assert.NotNull(jsonResult.Value);

        // Verify the anonymous object properties via reflection
        var value = jsonResult.Value!;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        Assert.True((bool)successProp!.GetValue(value)!);
        Assert.Equal(0, (int)countProp!.GetValue(value)!);
    }

    [Fact]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Enqueue some notifications via the service
        using var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
        svc.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value!;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");
        var notificationsProp = value.GetType().GetProperty("notifications");

        Assert.True((bool)successProp!.GetValue(value)!);
        Assert.Equal(2, (int)countProp!.GetValue(value)!);

        var notifications = notificationsProp!.GetValue(value) as List<Notification>;
        Assert.NotNull(notifications);
        Assert.Equal(2, notifications!.Count);
    }

    [Fact]
    public void GetNotifications_LimitsTo10()
    {
        using var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value!;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(10, (int)countProp!.GetValue(value)!);
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        var result = _controller.MarkAsRead(1);

        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value!;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(value)!);
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void GetNotifications_DequeuesMessages()
    {
        using var svc = new NotificationService();
        svc.SendNotification("Student", "1", EntityOperation.CREATE);

        // First call dequeues
        _controller.GetNotifications();

        // Second call should get empty
        var result = _controller.GetNotifications();
        var jsonResult = Assert.IsType<JsonResult>(result);
        var value = jsonResult.Value!;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(0, (int)countProp!.GetValue(value)!);
    }
}

