using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateSeededContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockLogger = new Mock<ILogger<CoursesController>>();

        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
        try { Directory.Delete(_tempDir, true); } catch { }
    }

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var mock = new Mock<IFormFile>();
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
        return mock.Object;
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(viewResult.Model);
        Assert.Equal(3, model.Count());
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithCourse()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<Course>(viewResult.Model);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    // --- Create POST ---

    [Fact]
    public void Create_POST_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.NotNull(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_POST_ValidCourse_WithValidImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Image Course",
            Credits = 4,
            DepartmentID = 1
        };
        var file = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, file);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        var saved = _context.Courses.Find(8888);
        Assert.NotNull(saved);
        Assert.StartsWith("/Uploads/TeachingMaterials/", saved!.TeachingMaterialImagePath);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 7777, DepartmentID = 1 };

        var result = _controller.Create(course, null!);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_POST_InvalidFileExtension_ReturnsModelError()
    {
        var course = new Course
        {
            CourseID = 7776,
            Title = "Bad Extension",
            Credits = 3,
            DepartmentID = 1
        };
        var file = CreateMockFormFile("document.pdf", 1024);

        var result = _controller.Create(course, file);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        Assert.Contains("valid image file", _controller.ModelState["teachingMaterialImage"]!.Errors[0].ErrorMessage);
    }

    [Fact]
    public void Create_POST_FileTooLarge_ReturnsModelError()
    {
        var course = new Course
        {
            CourseID = 7775,
            Title = "Big File",
            Credits = 3,
            DepartmentID = 1
        };
        var file = CreateMockFormFile("big.jpg", 6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, file);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        Assert.Contains("5MB", _controller.ModelState["teachingMaterialImage"]!.Errors[0].ErrorMessage);
    }

    [Theory]
    [InlineData(".txt")]
    [InlineData(".exe")]
    [InlineData(".doc")]
    [InlineData(".pdf")]
    [InlineData(".svg")]
    public void Create_POST_DisallowedExtensions_ReturnsError(string extension)
    {
        var course = new Course
        {
            CourseID = 6000,
            Title = "ExtTest",
            Credits = 3,
            DepartmentID = 1
        };
        var file = CreateMockFormFile($"file{extension}", 1024);

        var result = _controller.Create(course, file);

        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void Create_POST_AllowedExtensions_AcceptsFile(string extension)
    {
        var courseId = 5000 + Math.Abs(extension.GetHashCode() % 999);
        var course = new Course
        {
            CourseID = courseId,
            Title = $"ExtTest{extension}",
            Credits = 3,
            DepartmentID = 1
        };
        var file = CreateMockFormFile($"file{extension}", 1024);

        var result = _controller.Create(course, file);

        Assert.IsType<RedirectToActionResult>(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_GET_NotFound_ReturnsNotFound()
    {
        var result = _controller.Edit(99999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_GET_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_POST_ValidCourse_RedirectsToIndex()
    {
        var course = _context.Courses.Find(1050)!;
        var editCourse = new Course
        {
            CourseID = course.CourseID,
            Title = "Updated Chemistry",
            Credits = course.Credits,
            DepartmentID = course.DepartmentID
        };
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = _controller.Edit(editCourse, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, DepartmentID = 1 };

        var result = _controller.Edit(course, null!);

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_POST_InvalidFileExtension_ReturnsError()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };
        _context.Entry(_context.Courses.Find(1050)!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        var file = CreateMockFormFile("doc.pdf", 1024);

        var result = _controller.Edit(course, file);

        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_POST_FileTooLarge_ReturnsError()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };
        _context.Entry(_context.Courses.Find(1050)!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        var file = CreateMockFormFile("big.png", 6 * 1024 * 1024);

        var result = _controller.Edit(course, file);

        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_GET_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Delete(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
    {
        var initialCount = _context.Courses.Count();
        var result = _controller.DeleteConfirmed(1050);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Equal(initialCount - 1, _context.Courses.Count());
    }

    [Fact]
    public void DeleteConfirmed_CourseWithImagePath_DeletesFile()
    {
        // Create a file to simulate existing upload
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var testFile = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(testFile, "fake image data");

        var course = _context.Courses.Find(1050)!;
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(1050);

        Assert.False(File.Exists(testFile));
    }
}

